const svg=$('#et-svg'), out=$('#et-out'), nSl=$('#et-n'), pSel=$('#et-p'), nVal=$('#et-n-val');
const cx=280, cyB=260, cyT=120, rB=90, rT=55, M=12;
function render(){
  const n=+nSl.value, p=+pSel.value; nVal.textContent='n = '+n;
  const insep=(p>0 && n%p===0), col=insep?'var(--mute)':'var(--green)';
  svg.innerHTML='';
  const l1=SVG('text',{x:40,y:cyB+4,'font-size':12,fill:'var(--mute)'}); l1.textContent='base 𝔾ₘ'; svg.appendChild(l1);
  const l2=SVG('text',{x:40,y:cyT+4,'font-size':12,fill:'var(--mute)'}); l2.textContent='cover 𝔾ₘ'; svg.appendChild(l2);
  svg.appendChild(SVG('circle',{cx,cy:cyB,r:rB,fill:'none',stroke:'var(--line)'}));
  svg.appendChild(SVG('circle',{cx,cy:cyT,r:rT,fill:'none',stroke:'var(--line)'}));
  for(let k=0;k<M;k++){ const th=2*Math.PI*k/M;
    svg.appendChild(SVG('circle',{cx:cx+rB*Math.cos(th),cy:cyB+rB*Math.sin(th),r:4,fill:'var(--blue)'}));
    for(let j=0;j<n;j++){ const phi=(th+2*Math.PI*j)/n;
      svg.appendChild(SVG('circle',{cx:cx+rT*Math.cos(phi),cy:cyT+rT*Math.sin(phi),r:3.2,fill:col,opacity:insep?0.55:0.95}));
      if(k===0){ const bx=cx+rB*Math.cos(th), by=cyB+rB*Math.sin(th);
        svg.appendChild(SVG('line',{x1:bx,y1:by,x2:cx+rT*Math.cos(phi),y2:cyT+rT*Math.sin(phi),stroke:col,opacity:0.3,'stroke-dasharray':'3 3'})); }
    }
  }
  ensureArrow(svg,'et-arr','var(--violet)');
  svg.appendChild(SVG('path',{d:`M ${cx+rT+30} ${cyT+10} L ${cx+rT+30} ${cyB-rB-6}`,stroke:'var(--violet)',fill:'none','stroke-width':1.4,'marker-end':'url(#et-arr)'}));
  const al=SVG('text',{x:cx+rT+40,y:(cyT+cyB)/2,'font-size':12,fill:'var(--violet)','font-style':'italic'}); al.textContent='z↦z^n'; svg.appendChild(al);
  out.textContent = p===0 ? `char 0 · n=${n} · fiber degree=${n} · étale (always separable in char 0) ✓`
    : insep ? `char ${p} · n=${n} · p | n, dt^n/dt ≡ 0 · NOT étale (inseparable) ✗`
    : `char ${p} · n=${n} · gcd(n,p)=1 · étale of degree ${n}, Galois group μ_${n} ✓`;
}
nSl.addEventListener('input',render); pSel.addEventListener('change',render); render();

