const pSel=$('#jc-p'), nSl=$('#jc-n'), nv=$('#jc-nv'), out=$('#jc-out');
function render(){
  const p=+pSel.value,n=+nSl.value; nv.textContent='n = '+n;
  const sep = (p===0) || (n%p!==0);
  out.textContent = sep
    ? 'f(t)=t^n-u has derivative n t^{n-1} not identically zero in char '+(p||'0')+'. Fibers are separable, so finite map is étale away from t=0 singularities.'
    : 'p divides n (p='+p+'). Then derivative n t^{n-1} ≡ 0, so every root is multiple: purely inseparable extension, not étale.';
}
pSel.addEventListener('change',render); nSl.addEventListener('input',render); render();

