const sel=$('#la-sel'), out=$('#la-out'), svg=$('#la-svg');
const gSl=$('#la-g'), dSl=$('#la-d'), gVal=$('#la-g-val'), dVal=$('#la-d-val');
const gRow=$('#la-g-row'), dRow=$('#la-d-row');
function bettiOf(kind){
  if(kind==='curve'){ const g=+gSl.value; return {dim:1,b:[1,2*g,1],name:`curve g=${g}`}; }
  if(kind==='p2') return {dim:2,b:[1,0,1,0,1],name:'ℙ²'};
  if(kind==='ExE') return {dim:2,b:[1,4,6,4,1],name:'E×E'};
  const d=+dSl.value; // smooth surface deg d in ℙ³: b2=d³-4d²+6d-2, h^{2,0}=(d-1)(d-2)(d-3)/6
  const b2=d*d*d-4*d*d+6*d-2, h20=(d-1)*(d-2)*(d-3)/6;
  return {dim:2,b:[1,0,b2,0,1],name:`surface deg ${d}, h^{2,0}=${h20}`};
}
function render(){
  const kind=sel.value;
  gRow.style.display=(kind==='curve')?'':'none'; dRow.style.display=(kind==='surf')?'':'none';
  gVal.textContent='g = '+gSl.value; dVal.textContent='d = '+dSl.value;
  const {dim,b,name}=bettiOf(kind);
  svg.innerHTML='';
  const W=60,H=60,gap=10,n=b.length,x0=(560-n*W-(n-1)*gap)/2,y0=40;
  for(let i=0;i<n;i++){ const x=x0+i*(W+gap), c=b[i]===0?'var(--panel2)':'var(--blue)';
    svg.appendChild(SVG('rect',{x,y:y0,width:W,height:H,rx:6,fill:c,opacity:0.22,stroke:c,'stroke-width':1.4}));
    const v=SVG('text',{x:x+W/2,y:y0+H/2+6,'text-anchor':'middle','font-size':20,fill:'var(--ink)','font-weight':600}); v.textContent=b[i]; svg.appendChild(v);
    const it=SVG('text',{x:x+W/2,y:y0-8,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}); it.textContent='b_'+i; svg.appendChild(it);
  }
  const chi=b.reduce((a,v,i)=>a+(i%2?-v:v),0);
  const ct=SVG('text',{x:280,y:y0+H+30,'text-anchor':'middle','font-size':13,fill:'var(--yellow)'}); ct.textContent='χ(X) = Σ (−1)^i b_i = '+chi; svg.appendChild(ct);
  out.textContent=`${name} · dim=${dim} · Betti [${b.join(', ')}] · χ=${chi} · matches classical Betti ✓ (comparison theorem)`;
}
sel.addEventListener('change',render); gSl.addEventListener('input',render); dSl.addEventListener('input',render); render();

