const lSel=$('#tw-l'), nSl=$('#tw-n'), nv=$('#tw-nv'), svg=$('#tw-svg'), out=$('#tw-out');
function render(){
  const l=+lSel.value,n=+nSl.value; nv.textContent='n = '+n; svg.innerHTML='';
  for(let k=1;k<=n;k++){
    const x=40+(k-1)*62, y=70;
    svg.appendChild(SVG('rect',{x,y,width:50,height:42,rx:6,fill:'var(--panel2)',stroke:'var(--line)'}));
    const t=SVG('text',{x:x+25,y:y+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'}); t.textContent='ℤ/'+(l**k)+'ℤ'; svg.appendChild(t);
    const h=SVG('text',{x:x+25,y:y+34,'text-anchor':'middle','font-size':10,fill:'var(--cyan)'}); h.textContent='H^i'; svg.appendChild(h);
    if(k<n) drawArrow(svg,[x+52,y+21],[x+60,y+21],{color:'var(--violet)',pad1:0,pad2:0,markerId:'tw-arr'});
  }
  out.textContent='Tower: H^i(X,ℤ/'+l+'^n) with transition maps mod ℓ^k. Increasing n refines congruence data; lim← gives a ℤ_'+l+'-module, then ⊗ℚ_'+l+' yields H^i(X,ℚ_'+l+').';
}
lSel.addEventListener('change',render); nSl.addEventListener('input',render); render();

