}
lSel.addEventListener('change',render); nSl.addEventListener('input',render); render();

const sel=$('#lf-sel'), qSel=$('#lf-q'), nSl=$('#lf-n'), nv=$('#lf-n-val');
const gSl=$('#lf-g'), gv=$('#lf-g-val'), aSl=$('#lf-a'), av=$('#lf-a-val');
const mSl=$('#lf-m'), mv=$('#lf-m-val'), out=$('#lf-out');
const nW=$('#lf-n-wrap'), gW=$('#lf-g-wrap'), aW=$('#lf-a-wrap');
function render(){
  const kind=sel.value, q=+qSel.value, m=+mSl.value;
  nv.textContent='n = '+nSl.value; gv.textContent='g = '+gSl.value; av.textContent='a_q = '+aSl.value; mv.textContent='m = '+m;
  nW.style.display = (kind==='pn')?'':'none';
  gW.style.display = (kind==='curve')?'':'none'; gv.style.display = (kind==='curve')?'':'none';
  aW.style.display = (kind==='curve')?'':'none'; av.style.display = (kind==='curve')?'':'none';
  if(kind==='pn'){
    const n=+nSl.value;
    // H^{2i}(ℙ^n) one-dimensional, Frobenius acts as q^i. All odd cohomology vanishes.
    let trace=0, parts=[];
    for(let i=0;i<=n;i++){ const t=Math.pow(q,i*m); trace += t; parts.push('q^{'+(i*m)+'}'); }
    // point count: (q^{m(n+1)}-1)/(q^m-1)
    const Nm = (Math.pow(q,m*(n+1))-1)/(Math.pow(q,m)-1);
    out.textContent = `ℙ^${n} / 𝔽_${q}: Σ (−1)^i Tr(F^${m} | H^i) = ${parts.join(' + ')} = ${trace}; #ℙ^${n}(𝔽_{${q}^${m}}) = ${Nm} ✓`;
  } else {
    const g=+gSl.value, a=+aSl.value;
    // one pair (α, β=q/α) with α+β=a, take g copies for simplicity (same eigenvalue pair repeated g times → trace ×g)
    // use recurrence p_m = a p_{m-1} - q p_{m-2}, p_0=2, p_1=a, then Tr(F^m | H^1) = g * p_m
    const P=[2,a]; for(let k=2;k<=m;k++) P.push(a*P[k-1]-q*P[k-2]);
    const trH0 = 1, trH2 = Math.pow(q,m), trH1 = g*P[m];
    const alt = trH0 - trH1 + trH2;
    const qm = Math.pow(q,m);
    out.textContent = `curve g=${g}, a_q=${a}, q=${q}: Tr(F^${m} | H^0)=1, Tr(F^${m} | H^1)=${g}·${P[m]}=${trH1}, Tr(F^${m} | H^2)=${trH2}. #X(𝔽_{${q}^${m}}) = 1 − ${trH1} + ${qm} = ${alt}.`;
  }
}
[sel,qSel,nSl,gSl,aSl,mSl].forEach(el=>el.addEventListener('input',render));
sel.addEventListener('change',render); qSel.addEventListener('change',render);
render();

