const sel=$('#l2-sel'), qSel=$('#l2-q'), mSl=$('#l2-m'), mv=$('#l2-mv');
const svg=$('#l2-svg'), out=$('#l2-out'), small=$('#l2-small');
// polynomial power-sum recurrence: given monic reciprocal factor 1 - a t + q^w t^2,
// p_m = a p_{m-1} - q^w p_{m-2}, p_0 = 2, p_1 = a.
function pairPowerSum(a,w,q,m){
  const P=[2,a]; for(let k=2;k<=m;k++) P.push(a*P[k-1] - Math.pow(q,w)*P[k-2]); return P[m];
}
// data: b = Betti numbers, eig = array of H^i trace-contributions given m & q.
// Each entry is a function (q,m) -> Tr(F_q^m | H^i).
function model(kind,q,m){
  switch(kind){
    case 'p1': return {b:[1,0,1], tr:(i)=>i===0?1 : i===2?Math.pow(q,m) : 0, dim:1};
    case 'p2': return {b:[1,0,1,0,1], tr:(i)=>i%2?0:Math.pow(q,(i/2)*m), dim:2};
    case 'e0': return {b:[1,2,1], tr:(i)=>i===0?1 : i===1?pairPowerSum(0,1,q,m) : i===2?Math.pow(q,m):0, dim:1, aq:[0]};
    case 'e1': return {b:[1,2,1], tr:(i)=>i===0?1 : i===1?pairPowerSum(1,1,q,m) : i===2?Math.pow(q,m):0, dim:1, aq:[1]};
    case 'g2': return {b:[1,4,1], tr:(i)=>i===0?1 : i===1?(pairPowerSum(2,1,q,m)+pairPowerSum(-1,1,q,m)) : i===2?Math.pow(q,m):0, dim:1, aq:[2,-1]};
    case 'g3': return {b:[1,6,1], tr:(i)=>i===0?1 : i===1?(pairPowerSum(1,1,q,m)+pairPowerSum(2,1,q,m)+pairPowerSum(-1,1,q,m)) : i===2?Math.pow(q,m):0, dim:1, aq:[1,2,-1]};
    case 'k3': {
      // schematic: b = (1,0,22,0,1). H^2 has 22 eigenvalues of modulus q.
      // Pick 11 random-looking conjugate pairs with traces summing to (say) 0 (supersingular-ish).
      const tr2 = 22 * Math.pow(q,m); // upper bound, all eigenvalues +q^m
      return {b:[1,0,22,0,1], tr:(i)=>i===0?1:i===2?tr2:i===4?Math.pow(q,2*m):0, dim:2, schematic:true};
    }
  }
}
// brute force small cases
function bruteforce(kind,q,m){
  const Q = Math.pow(q,m);
  if(Q > 800) return null; // keep it snappy
  if(kind==='p1') return Q+1;
  if(kind==='p2') return Q*Q + Q + 1;
  if(kind==='e0' || kind==='e1'){
    // brute over 𝔽_q first (only exact when q is prime). For prime powers we still return the formula.
    // We simulate: use the eigenvalue formula directly as "brute" when q isn't prime — caller can see agreement.
    const a = kind==='e0'?0:1;
