function isPrime(n){ if(n<2) return false; for(let k=2;k*k<=n;k++) if(n%k===0) return false; return true; }
function primesUpTo(N){ const r=[]; for(let n=2;n<=N;n++) if(isPrime(n)) r.push(n); return r; }
function apEll(p){
  // y^2 = x^3 - x + 1; Hasse: a_p = p + 1 - #E(F_p), including point at infinity.
  if(p===2){ // special: enumerate over F_2 directly
    let N=1; // infinity
    for(let x=0;x<2;x++) for(let y=0;y<2;y++){ if(((y*y)%2) === (((x*x*x - x + 1)%2 + 2)%2)) N++; }
    return 2+1 - N;
  }
  let N=1;
  for(let x=0;x<p;x++){
    const r = (((x*x*x - x + 1)%p)+p)%p;
    if(r===0){ N+=1; continue; }
    // Euler criterion: r^((p-1)/2) mod p
    let e=1, base=r, exp=(p-1)/2;
